// Extract Task Context + Collective Memory
const requestBody = $input.item.json.body;

const task_id = requestBody.task_id;
const task_title = requestBody.task_title;
const task_description = requestBody.task_description || '';
const user_inputs = requestBody.user_inputs || {};
const project_id = requestBody.project_id || requestBody.shared_memory?.project_id;

// Load Collective Memory
let projectMemory = [];
try {
  const { rows } = await $supabase.query(
    'SELECT * FROM project_memory WHERE project_id = $1 ORDER BY created_at DESC LIMIT 20',
    [project_id]
  );
  projectMemory = rows || [];
} catch (err) { console.error('Memory load error:', err); }

// Load Brand Memory
let brandMemory = {};
try {
  const { rows } = await $supabase.query(
    'SELECT * FROM brand_memory WHERE project_id = $1',
    [project_id]
  );
  brandMemory = rows[0] || {};
} catch (err) { console.error('Brand memory error:', err); }

return {
  json: {
    task_id,
    task_title,
    task_description,
    user_inputs,
    project_id,
    project_memory: projectMemory,
    brand_memory: brandMemory,
    original_request: requestBody
  }
};

// Parse Milo Response & Extract Commands
const agentResponse = $input.item.json;
const responseText = agentResponse.output || agentResponse.text || '';

// Extract COMMAND blocks
const commandPattern = /COMMAND:\s*([A-Z_]+)[\s\S]*?REASON:\s*([^\n]+)[\s\S]*?PAYLOAD:\s*(\{[\s\S]*?\})/g;
const commands = [];

let match;
while ((match = commandPattern.exec(responseText)) !== null) {
  const [_, command, reason, payloadStr] = match;
  try {
    const payload = JSON.parse(payloadStr);
    commands.push({ command, reason, payload });
  } catch (e) {
    console.error('Parse error:', e);
  }
}

const taskContext = $('Extract Context').item.json;

return {
  json: {
    agent_response: {
      message: responseText.split('COMMAND:')[0].trim(),
      agent_used: 'milo',
      commands,
      raw_response: responseText
    },
    task_context: taskContext
  }
};

// Execute Write-Back Commands
const { commands } = $input.item.json.agent_response;
const { project_id, task_id } = $input.item.json.task_context;

for (const cmd of commands) {
  try {
    switch (cmd.command) {
      case 'ADD_FILE':
        await $supabase.query(
          'INSERT INTO project_files (project_id, file_type, file_name, file_base64, metadata, created_by) VALUES ($1, $2, $3, $4, $5, $6)',
          [project_id, cmd.payload.file_type, cmd.payload.file_name, cmd.payload.file_base64, JSON.stringify(cmd.payload.metadata || {}), 'milo']
        );
        break;

      case 'UPDATE_TASK_STATUS':
        await $supabase.query(
          'UPDATE tasks SET status = $1, completion_notes = $2, completed_at = NOW(), updated_at = NOW() WHERE id = $3',
          [cmd.payload.status, cmd.payload.completion_notes, cmd.payload.task_id]
        );
        break;

      case 'MEMORY_WRITE':
        await $supabase.query(
          'INSERT INTO project_memory (project_id, agent_id, task_id, action, summary, key_findings, deliverables, recommendations) VALUES ($1, $2, $3, $4, $5, $6, $7, $8)',
          [project_id, 'milo', task_id, cmd.payload.action || 'CREATIVE_COMPLETED', cmd.payload.summary, JSON.stringify(cmd.payload.key_findings || []), JSON.stringify(cmd.payload.deliverables || []), JSON.stringify(cmd.payload.recommendations || [])]
        );
        break;

      case 'NOTIFY_USER':
        await $supabase.query(
          'INSERT INTO notifications (project_id, type, title, message, metadata, created_by) VALUES ($1, $2, $3, $4, $5, $6)',
          [project_id, 'task_update', 'Milo a terminé', cmd.payload.message, JSON.stringify({ attachments: cmd.payload.attachments || [] }), 'milo']
        );
        break;
    }
  } catch (error) {
    console.error(`Error executing ${cmd.command}:`, error);
  }
}

return {
  json: {
    success: true,
    commands_executed: commands.length,
    agent_response: $input.item.json.agent_response
  }
};
